"""
MKT Context Commentary — Ezekiel chapters 29–32
Run: python3 scripts/zc-context-ezekiel-29-32.py

These four chapters are Ezekiel's Egypt oracle collection — the longest sustained
foreign-nation oracle sequence in the book (six dated oracles in chs 29-32 plus ch 33).

Key interpretive decisions:
- Ch29 vv6-7: reed staff = specific reference to Hophra's abortive Jerusalem relief (Jer 37:5-11),
  not merely a generic alliance-critique; this reading gives the oracle its historical precision
- Ch29 vv17-21: this is the LATEST dated oracle in Ezekiel (27th year = 571 BCE, 16 years after
  Jerusalem's fall); acknowledging Nebuchadnezzar received no plunder from Tyre (historically accurate)
  and promising Egypt as wages is theologically honest, not a "failed prophecy" correction
- Ch31 cedar allegory: Assyria-as-cedar is addressed to Egypt as a mirror, not as a separate oracle
  against Assyria; the form is "you will go where they went"
- Ch32 Sheol gallery: the nations in Sheol (Assyria, Elam, Meshech-Tubal, Edom, Sidonians) are
  presented in order of historical fall — a retrospective of imperial collapse from Ezekiel's present
- "Uncircumcised, slain by the sword" formula: repeated 8× in ch32 as the maximum shame category —
  not circumcision as such but covenant-less death by violence
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZEKIEL_CONTEXT = {
  "29": {
    "1": "<p>The date header — &#8220;tenth year, tenth month, twelfth day&#8221; — corresponds to January 7, 587 BCE (Julian), approximately 18 months into Nebuchadnezzar's siege of Jerusalem (which began in December 589 BCE). This is the fifth of the six dated Egypt oracles and one of only three oracles in Ezekiel dated within the siege-period of 589-587 BCE (alongside 24:1 and 30:20). The context is critical: Jerusalem is surrounded, the Egyptian army under Hophra/Apries has moved toward Judah to relieve it (Jer 37:5), and the oracle against Egypt arrives at precisely the moment when exiles might pin their hopes on Egyptian intervention.</p>",
    "2": "<p>&#8220;Set your face against Pharaoh&#8221; — the same confrontation formula used against Jerusalem (Ezek 6:2), Judah (21:2), Ammon (25:2), Tyre (28:21), and Sidon (28:22). By applying the identical formula to Egypt that YHWH used against his own people and their neighbors, Ezekiel places Egypt within the same theological framework: no nation stands outside YHWH's jurisdiction. The formula originated in Israelite siege rhetoric (the commander &#8220;set his face against&#8221; a fortified city) and became Ezekiel's characteristic expression of prophetic-divine opposition. &#8220;Prophesy against him and against all Egypt&#8221; extends the judgment from the individual ruler to the entire nation — Pharaoh's pride implicates Egypt.</p>",
    "3": "<p>Pharaoh king of Egypt is identified as &#8220;the great sea creature lying in the midst of his rivers&#8221; (<em>hatannin hagadol harovets betokh yeoreiv</em>). <em>Tannin</em> (sea creature/monster) is the chaos-dragon of ANE cosmology — cognate with the Ugaritic <em>tnn</em> who fights Baal, and related to the Babylonian Tiamat whom Marduk slays. In Egyptian iconography, Pharaoh was associated with the Nile crocodile (Sobek) and with the serpent-dragon Apophis, the enemy of Re. Ezekiel collapses these traditions: Pharaoh is a chaos creature whose domain is the Nile. The boast &#8220;My Nile is my own; I made it for myself&#8221; (<em>li yeori vaani asitini</em>) echoes the Pharaonic theology that the annual Nile flood was mediated by the king's divine status — the pharaoh's ritual power was believed to sustain the Nile's fertility. This is the precise claim YHWH will refute: the Nile belongs to YHWH, not Pharaoh, and YHWH will prove it by removing Pharaoh from it.</p>",
    "4": "<p>Fish-hook imagery (&#8220;I will put hooks in your jaws&#8221;) depicts YHWH as the divine fisher-king who hauls out the chaos monster from its native element. This inverts the normal ANE imagery where the great fish is a symbol of abundance and divine provision — here it becomes the means of humiliation. The fish clinging to Pharaoh's scales are his people and the armies dependent on him — they will be dragged out together. The same hook imagery appears in Amos 4:2 (Israel will be &#8220;taken away with hooks&#8221;) and in Ezek 38:4 (YHWH will put hooks in Gog's jaws). In Egyptian military iconography, prisoners were often depicted with hooks through their lips or noses — a deliberately humiliating reversal of Egyptian conquering-imagery.</p>",
    "5": "<p>Thrown into the wilderness — the reversal of the Exodus. In the Exodus, Israel was freed from Egypt and led through the wilderness to the land; here, Egypt's king is expelled from his river to the wilderness and left unburied. &#8220;Not be gathered or collected&#8221; (<em>lo-teasef velo tikavets</em>) — proper burial was a deep concern in the ancient world; unburied corpses were the ultimate disgrace (Deut 28:26; Jer 7:33; 8:2). Leaving Pharaoh's body as &#8220;food to the beasts of the field and birds of the air&#8221; is the specific covenant-curse of Deut 28:26 applied to Egypt's king. The wilderness-exposure imagery also evokes the fate of Egypt's army in the Red Sea — another reversal: previously Egypt's enemies drowned in the sea; now Egypt is exposed in the desert.</p>",
    "6": "<p>&#8220;All the inhabitants of Egypt will know that I am the LORD, because they have been a staff of reed to the house of Israel&#8221; — the &#8220;knowledge formula&#8221; (<em>veyadeu ki ani YHWH</em>) appears 72 times in Ezekiel and marks every major judgment and restoration oracle. YHWH's actions produce knowledge of who he is — his identity is revealed through historical events. The &#8220;staff of reed&#8221; (<em>mikkel qaneh</em>) metaphor already appeared in the Assyrian threat to Hezekiah (2 Kings 18:21 = Isa 36:6): &#8220;you are relying on Egypt, that broken reed of a staff, which will pierce the hand of any man who leans on it.&#8221; Ezekiel applies the same image to Judah's continued reliance on Egypt despite that earlier warning — 130 years later, the same mistake, the same result.</p>",
    "7": "<p>The reed staff imagery is extended mechanically: when Israel &#8220;grasped you with their hand, you splintered and tore their shoulder.&#8221; Egypt's military intervention on Judah's behalf (Hophra's march toward Jerusalem in 588 BCE, documented in Jer 37:5-11) briefly caused Nebuchadnezzar to lift the siege — but Egypt withdrew without engaging, and the siege resumed. The physical image (a walking-staff that splinters cuts the user's palm; a weight-bearing staff that breaks wrenches the shoulder) perfectly captures Egypt's half-hearted intervention: Egypt's support caused damage rather than help, because Hophra withdrew at the critical moment, forcing Judah to re-face the Babylonian siege alone and with diminished hope.</p>",
    "8": "<p>The &#8220;sword against you&#8221; formula (<em>veheveiti aleykha cherev</em>) is the divine-warrior declaration: YHWH himself is the attacker, using Nebuchadnezzar's sword as his instrument (made explicit in 29:19). The cutting off of &#8220;both man and beast&#8221; (<em>adam uvehemah</em>) mirrors the covenant-curse language of Lev 26:22 (beasts cutting off livestock) and Deut 28:31 (loss of animals). The destruction extends beyond human casualties to the agricultural economy — Egypt's cattle herds grazed on the Nile's floodplain, and their destruction signals the collapse of Egypt's economic foundations.</p>",
    "9": "<p>The knowledge formula (&#8220;they will know that I am the LORD&#8221;) appears again, this time grounding the judgment in Pharaoh's specific sin: the claim of Nile-ownership and self-creation. The theological point is sharp — Egypt's judgment is not random but proportionate: Egypt claimed divine powers over the Nile, and YHWH will demonstrate that the Nile is his to give or take. The same logic governs all the Egypt oracles: Egypt's fall is not merely political conquest but a demonstration of YHWH's exclusive sovereignty over creation, including the natural resources that Egypt falsely attributed to its own divine king.</p>",
    "10": "<p>&#8220;From Migdol to Syene, as far as the border of Cush&#8221; — Migdol (<em>Migdol</em>) was a fortress city on Egypt's northeastern border in the Sinai delta region (identified with Tell el-Borg or Tell el-Abqa); it was also the location where some Jewish refugees from Jerusalem settled after 586 BCE (Jer 44:1). Syene (Aswan, at the first cataract of the Nile) was Egypt's southern border with Nubia/Cush, site of the famous Elephantine Jewish colony. The phrase is therefore equivalent to &#8220;from north to south&#8221; — the entire length of the Nile valley. The rhetorical gesture (naming the extreme boundaries) is the same as Israel's &#8220;from Dan to Beersheba&#8221; — totality expressed through polar extremes.</p>",
    "11": "<p>&#8220;No human foot will pass through it, no animal's foot will pass through it, and it will not be inhabited for forty years&#8221; — the forty-year desolation is the covenant-discipline number (forty years of wilderness wandering; forty days on Sinai; forty days of Elijah's journey). The desolation is total: no foot — animal or human — will traverse it. This hyperbolic language follows the pattern of the Sodom-and-Gomorrah oracle in Isa 13:20 (Babylon: &#8220;it will never be inhabited or lived in for all generations; no Arab will pitch his tent there&#8221;). Egypt was indeed weakened after Nebuchadnezzar's campaign (568-567 BCE) but was not literally uninhabited for forty years — the prophetic language uses covenant-number (forty) to signal the totality and divine purposiveness of the discipline.</p>",
    "12": "<p>The desolation of Egypt &#8220;in the midst of desolated lands&#8221; places Egypt within the broader landscape of Babylonian conquest — Judah, Phoenicia, and the surrounding nations were all in various states of devastation. Egypt's cities &#8220;among ruined cities&#8221; (bevein arim chorevot) reflects the actual condition of the eastern Mediterranean world after Nebuchadnezzar's campaigns: Tyre besieged for 13 years, Jerusalem destroyed, Ammon and Moab subjugated. The scattering of Egyptians among the nations mirrors exactly what happened to Israel — YHWH treats Egypt with the same covenant-curse logic he applied to his own people, universalizing the judgment structure.</p>",
    "13": "<p>&#8220;Yet&#8221; (<em>ki koh amar Adonai YHWH veqibatzti</em>) — the restoration promise interrupts the desolation oracle in the same pattern as the restoration promises within the Israel-judgment oracles (Ezek 11:17; 20:41-42; 36:24). Egypt will be gathered from the nations at the end of forty years — a reversal of its scattering. The &#8220;gathering from the peoples&#8221; (<em>qibatzti</em>) language is the same used for Israel's eschatological restoration (20:34, 41; 28:25; 34:13; 36:24; 37:21; 38:8). YHWH's gathering formula is not exclusive to Israel — it belongs to his sovereign management of all nations, and Egypt receives a form of it, though on much reduced terms.</p>",
    "14": "<p>Restoration to &#8220;Pathros, the land of their origin&#8221; — Pathros (Hebrew <em>Patros</em>, Egyptian <em>Pa-to-Res</em>, &#8220;the southern land&#8221;) is Upper Egypt, the ancient heartland of Egyptian civilization centered on Thebes. The 26th Dynasty (the Saite period, ca. 664-525 BCE) had its origins in Lower Egypt (the Delta), ruling a reunified Egypt from Sais. Pathros as origin-land suggests Ezekiel envisions Egypt returning to its ancient core territory rather than dominating the Delta and the near eastern corridor. The &#8220;lowly kingdom&#8221; (<em>mamlekhet shefalah</em>) is not an insult but a categorical diminution: Egypt will persist as a nation but will never again be the regional hegemon that Israel's kings sought as an ally.</p>",
    "15": "<p>&#8220;The humblest of kingdoms, and it will no longer exalt itself over the nations&#8221; — this is fulfilled in broad historical outline. After the Babylonian and then Persian conquest (Cambyses invaded Egypt in 525 BCE), Egypt never again achieved independent regional hegemony. It remained a wealthy but politically subordinate province: Persian satrapy (525-332 BCE), Macedonian/Ptolemaic kingdom (332-30 BCE), and Roman province (30 BCE). The &#8220;I will diminish them&#8221; (<em>umitatim</em>) formula is the precise reversal of the reed-staff offense: Egypt claimed to prop up others; YHWH will make it so small it cannot prop up anyone, including itself.</p>",
    "16": "<p>&#8220;Egypt will no longer be a source of confidence for the house of Israel&#8221; (<em>velo-yihyeh od leveit Yisrael limivtach</em>) — <em>mivtach</em> (confidence/trust) is the wisdom vocabulary for misplaced reliance; Proverbs uses it for trusting in wealth (Prov 11:28), and the Psalms for trusting in anything other than YHWH (Ps 118:8-9). Judah's chronic policy of seeking Egyptian alliance against Assyria and Babylon is the historical background: Isaiah 31:1 (&#8220;Woe to those who go down to Egypt for help&#8221;); Jer 2:36 (&#8220;How cheap you made yourself by going to Assyria and Egypt&#8221;). The exile cure for this misplaced confidence is Egypt's reduction: when Egypt is a &#8220;lowly kingdom,&#8221; it will no longer tempt Israel to look southward instead of to YHWH.</p>",
    "17": "<p>The date shift — &#8220;twenty-seventh year, first month, first day&#8221; = April 26, 571 BCE — places this as the latest dated oracle in the entire book of Ezekiel, coming 16 years after the fall of Jerusalem and 26 years after Ezekiel's call. The insertion of this later oracle into the earlier Egypt collection (29:1, dated 587 BCE) is unusual but intelligible: both concern Egypt's fate and Nebuchadnezzar's role. The occasion is the end of Nebuchadnezzar's 13-year siege of Tyre (ca. 585-573 BCE) — documented in Josephus who cites Phoenician records, and implied by Ezekiel's reference to bald heads and rubbed shoulders from the siege-labor.</p>",
    "18": "<p>&#8220;Every head went bald and every shoulder was rubbed raw&#8221; — a vivid description of the physical toll of siege warfare: soldiers wore helmets that abrared the scalp; carrying siege equipment (battering rams, lumber for siege towers, earth for ramps) rubbed shoulders raw. The Assyrian reliefs of siege operations (like the Lachish siege relief) show armies carrying exactly this kind of equipment. Nebuchadnezzar &#8220;received no payment from Tyre&#8221; because Tyre (built on an island offshore) was essentially impregnable in this period and eventually negotiated terms rather than surrendering its wealth intact. Alexander the Great finally took Tyre in 332 BCE by building a causeway — Nebuchadnezzar lacked the means to do so.</p>",
    "19": "<p>&#8220;I am giving the land of Egypt to Nebuchadnezzar king of Babylon&#8221; — the frank acknowledgment that Nebuchadnezzar served YHWH's purpose at Tyre but received no material reward, and that Egypt is promised as compensation, is remarkable for its theological honesty. It treats Nebuchadnezzar as a hired laborer (the imagery of payment, wages, and service is commercial/contractual) who has not yet received his due. The oracle is dated to 571 BCE, when Nebuchadnezzar was already engaged in his Egyptian campaign (568-567 BCE is the likely date of Nebuchadnezzar's actual invasion of Egypt, attested in fragmentary Babylonian records).</p>",
    "20": "<p>&#8220;I have given him the land of Egypt as his wage for what he did, because he and his army worked for me, declares the Lord GOD&#8221; — the theological claim here is audacious: Nebuchadnezzar's Babylonian army is described as YHWH's workforce (<em>avad li</em>, worked for me). This extends the Cyrus-as-shepherd logic of Isa 44:28 and Isa 45:1 backward: even before Cyrus, Nebuchadnezzar was YHWH's instrument. The king who destroyed Jerusalem, deported Judah, and besieged Tyre is described as working for YHWH — not despite his wickedness, but as the vehicle through which YHWH's judgment purposes were executed. This is consistent with Ezekiel's theology of YHWH's universal sovereignty over all nations' military history.</p>",
    "21": "<p>&#8220;On that day I will cause a horn to sprout for the house of Israel&#8221; — the horn (<em>qeren</em>) is the biblical symbol of royal power and strength (Ps 92:10; 132:17; 148:14). A sprouting horn (<em>atzmich qeren</em>) is a Davidic/messianic image — Ps 132:17 uses the same verb: &#8220;there I will make a horn sprout for David.&#8221; In the LXX and later tradition, this was read as messianic. The oracle thus ends with an unexpected messianic note: Egypt's humiliation and Nebuchadnezzar's wages are the context in which YHWH will restore Davidic strength to Israel. &#8220;I will open your mouth&#8221; refers to Ezekiel's prophetic speech being restored — 3:27 established his silence would end when YHWH opened his mouth again (fully enacted in 33:21-22 after Jerusalem's fall).</p>"
  },
  "30": {
    "1": "<p>The oracle is undated — the only undated oracle in the Egypt collection, suggesting it may have been composed as a generalized theological statement about the Day of the LORD rather than a specific dated prophecy. The undated status places it in contrast with the precisely dated oracles surrounding it (29:1, 29:17, 30:20, 31:1, 32:1, 32:17), highlighting that the &#8220;Day of the LORD is near&#8221; is not a calculation but a theological certainty.</p>",
    "2": "<p>&#8220;Wail — alas for the day!&#8221; (<em>heyliyl ha yom</em>) — the prophetic wail (<em>heyliyl</em>, howl) is the sound of professional mourners at a death. Amos 8:3 uses it for the day when temple songs become wailing; Isa 13:6 uses it for the Day of the LORD against Babylon; Isa 23:1 for the oracle against Tyre. Ezekiel applies it here to Egypt. The &#8220;day&#8221; language anticipates v. 3's explicit &#8220;Day of the LORD&#8221; — the wailing is appropriate because the Day of the LORD, though salvation for Israel in some contexts, is purely judgment in its application to the nations who rebelled against YHWH's cosmic order.</p>",
    "3": "<p>&#8220;The day of the LORD is near — a day of cloud. It will be the time of the nations&#8221; (<em>ki qarov yom vaqarov yom-YHWH anan et-goyim yihyeh</em>) — the <em>Yom YHWH</em> tradition in the prophets originated as a day when YHWH would intervene decisively in history on behalf of Israel (originally assumed to be automatically favorable: Amos 5:18-20 corrects this assumption for Israel herself). In the foreign-nation oracles it is unambiguously judgment. &#8220;A day of cloud&#8221; (<em>anan</em>) recalls theophanic cloud-presence (the pillar of cloud in the wilderness, the cloud filling the tabernacle and temple) — but here it is a war-cloud: dark, threatening, obscuring. &#8220;Time of the nations&#8221; (<em>et goyim</em>) applies the Day of the LORD to all nations simultaneously, not just Egypt.</p>",
    "4": "<p>&#8220;Anguish will grip Ethiopia when the slain fall in Egypt; her wealth will be carried off&#8221; — Cush (Ethiopia/Nubia) was not merely Egypt's neighbor but had recently been Egypt's rulers: the 25th Dynasty (ca. 744-656 BCE) was Nubian, and Cushite kings like Taharqa and Tantamani had ruled Egypt and fought Assyria. By Ezekiel's time, Cush was a separate kingdom again (the 26th Dynasty was Saite/Egyptian), but deep cultural and economic ties remained. Cushite mercenaries served in the Egyptian army (Jer 46:9; Nah 3:9). Egypt's fall will destabilize Cush economically and militarily.</p>",
    "5": "<p>The coalition of Egypt's allies — Cush (Nubia), Put (Libya), Lud (possibly Lydia — Lydian mercenaries in the Egyptian army are mentioned by Herodotus), Cub (uncertain; possibly a Libyan tribe or Galatian mercenaries), and the &#8220;mixed peoples&#8221; (<em>erev</em>, literally &#8220;mixture/mingling&#8221;, referring to foreign mercenaries and residents in Egypt) — reflects the cosmopolitan military character of the Egyptian army in the Saite period. Herodotus (2.152, 154) describes the Saite kings bringing in Ionian and Carian mercenaries; the Egyptian military in this period was notable for its reliance on foreign troops. The &#8220;people of the land that is in league with them&#8221; (<em>uvney eretz habberit</em>) may refer to Judean refugees in Egypt (Jer 44) or to treaty-allied Canaanite states.</p>",
    "6": "<p>&#8220;Those who support Egypt will fall&#8221; — the entire security system of Egyptian alliances collapses together with Egypt itself. The covenant-partner nations that relied on Egypt (as Judah had done) will discover that Egypt cannot save them either. &#8220;From Migdol to Syene they will fall by the sword within her&#8221; — the polar-extremes formula from 29:10 is repeated, confirming the totality of the judgment. The word &#8220;proud strength&#8221; (<em>geion uzah</em>) echoes the same phrase used of Israel's pride in Lev 26:19 (&#8220;I will break down your proud strength&#8221;) — Egypt receives the same covenant-curse language that Israel received.</p>",
    "7": "<p>&#8220;Desolate in the midst of desolated lands, her cities will lie among ruined cities&#8221; — the description situates Egypt within the broader landscape of Babylonian conquest in the 6th century. Judah, Moab, Ammon, Philistia, Tyre, and Sidon were all in various states of destruction or subjugation. Egypt in ruins is not uniquely targeted by YHWH but joins the community of ruined nations — the comprehensive collapse of the pre-exilic political order. The Babylonian period was one of the great demographic and political disruptions of the ancient Near East, and Ezekiel's oracles interpret this disruption as YHWH's comprehensive judgments against pride and covenant-breach.</p>",
    "8": "<p>&#8220;They will know that I am the LORD when I set fire to Egypt and all her helpers are broken&#8221; — the knowledge formula applied to Egypt's destruction follows the same theological logic as in the Israel oracles: YHWH's actions produce knowledge of his identity. &#8220;Set fire to Egypt&#8221; is likely the military vocabulary of torch-and-siege (ancient armies routinely burned cities after conquest). The Babylonian destruction of Egyptian cities is attested in fragmentary records of Nebuchadnezzar's 568-567 BCE campaign (the Berlin fragments of the Babylonian Chronicle mention his Egyptian campaign). The &#8220;breaking of Egypt's helpers&#8221; means the end of the coalition described in vv. 4-6.</p>",
    "9": "<p>&#8220;Messengers will go out from me by ship to terrify the complacent Cush&#8221; — the news of Egypt's fall will travel by sea to Nubia/Ethiopia. The Nile-to-Red-Sea river system was a major commercial and communication route in the ancient world; Egyptian ships regularly traveled these waters. &#8220;Complacent Cush&#8221; (<em>Kush habetoah</em>) — confident in its remoteness and security — will be shaken when it learns that Egypt, its enormous northern neighbor and former master, has fallen. The same &#8220;complacent&#8221; language is used of Babylon in Isa 47:8 (&#8220;you who feel secure, who say in your heart I am and there is no one else besides me&#8221;).</p>",
    "10": "<p>&#8220;I will put an end to the multitude of Egypt by the hand of Nebuchadnezzar king of Babylon&#8221; — Nebuchadnezzar is named explicitly as YHWH's instrument against Egypt. This naming of a foreign king as YHWH's servant echoes Isa 44:28-45:1 (Cyrus named as shepherd and anointed) and Jer 25:9 (Nebuchadnezzar named as YHWH's servant against the nations). The &#8220;multitude of Egypt&#8221; (<em>hamon Mitzrayim</em>) is the vast military and population mass of Egypt — the single most powerful empire in the region at this time. That YHWH would use Babylon against Egypt is the ultimate statement of Babylonian hegemony as divinely appointed.</p>",
    "11": "<p>&#8220;The most ruthless of nations&#8221; (<em>arizey goyim</em>) is Ezekiel's characteristic epithet for the Babylonian army (also in 28:7; 31:12; 32:12). The Babylonian army's reputation for ruthlessness was historically well-founded: the destruction of Jerusalem (Lam 1:12-15; 2:1-9), the deportations, and the systematic dismantlement of subject kingdoms were all documented. The phrase functions as a paradoxical theological pointer: the most brutal human army is the instrument of divine justice. &#8220;Unsheathing swords against Egypt&#8221; — the sword-drawing gesture is the formal commencement of combat in ancient military protocol.</p>",
    "12": "<p>&#8220;I will make the Nile channels run dry&#8221; (<em>vehoravti yeorot venatarti aretz beyad reim</em>) — the Nile's seven branches (the Delta channels) were the geographic foundation of Lower Egypt's civilization. Blocking or diverting Nile channels was a known military tactic in the ancient world. The verb &#8220;sell the land into the hand of evil men&#8221; (<em>venatarti aretz beyad reim</em>) is commercial: YHWH is the divine landlord who transfers Egypt's lease to Babylon. &#8220;By the hand of foreigners&#8221; (<em>beyad zarim</em>) — the same phrase used in Ezek 28:7 for Tyre's destruction by strangers; YHWH delivers his owned territory to tenants of his choice.</p>",
    "13": "<p>&#8220;I will destroy the idols and put an end to the images in Memphis&#8221; — Memphis (Hebrew <em>Nof</em> or <em>Mof</em>, Egyptian <em>Men-nefer</em>) was the ancient administrative capital of Lower Egypt and the center of Ptah-worship. Ptah was the creator-deity of Memphis, the divine craftsman who created by speaking the word in his heart and on his tongue — a remarkable structural parallel to the Logos theology of Gen 1 and John 1. The &#8220;images&#8221; (<em>elilim</em>) of Memphis included Ptah, Sekhmet (lion-headed war-goddess), and Apis (the sacred bull). &#8220;No longer a prince in the land of Egypt&#8221; (<em>velo-yihyeh od nasi meeretz mitzrayim</em>) — after Alexander's conquest (332 BCE) and then Roman annexation (30 BCE), native Egyptian rule effectively ended.</p>",
    "14": "<p>Pathros (Upper Egypt), Zoan (Tanis), and Thebes (No) are three major centers of Egyptian political and religious power. Zoan/Tanis (<em>Tso-an</em>) in the Delta was the northern capital during the Tanite dynasties and was a major political center in the Saite period; the psalm tradition remembered Egypt by reference to Zoan (Ps 78:12, 43). Thebes (Egyptian <em>Waset</em>, Hebrew <em>No</em> or <em>No-Amon</em>) was the great southern capital and the center of Amun worship — its temples at Karnak and Luxor were the largest religious complex in the ancient world. The fall of Thebes to the Assyrians under Ashurbanipal in 663 BCE (referenced in Nah 3:8-10) was a living memory in Ezekiel's time — Egypt had rebuilt, but the memory of that earlier destruction provided a precedent for what Ezekiel now announces.</p>",
    "15": "<p>Pelusium (Hebrew <em>Sin</em>, Egyptian <em>Per-Amun</em>) was the fortified northeastern gateway to Egypt — the key military position controlling the land route from Asia into Egypt. Every major invasion of Egypt from the east (Assyrian, Babylonian, Persian, Macedonian) passed through or near Pelusium. Cambyses defeated Egypt at Pelusium in 525 BCE; Alexander encountered it in 332 BCE. The &#8220;stronghold of Egypt&#8221; (<em>mivtzar Mitzrayim</em>) title is apt: Pelusium was Egypt's first line of defense and its most fortified city. Thebes appears again — the double mention of Thebes (vv. 14 and 15-16) reflects its importance; it was Egypt's theological and cultural heart.</p>",
    "16": "<p>The city-catalog pattern in vv. 13-19 is similar to the Egyptian Execration Texts (clay figurines inscribed with enemies' names and ritually broken) and to the list of cities cursed in Amos 1-2 — the naming of cities in a judgment oracle both specifics and makes the judgment concretely applicable. &#8220;Pelusium will writhe in anguish, Thebes will be breached, Memphis will face daily distress&#8221; — three different verbs of suffering (<em>hil</em>/writhe, <em>hivvaqea</em>/breach, <em>tsarot yomam</em>/daily distress) applied to three of Egypt's greatest cities gives the oracle a varied rhetoric that prevents it from being merely formulaic repetition.</p>",
    "17": "<p>On (Greek <em>Heliopolis</em>, Egyptian <em>Iunu</em>) was the ancient seat of Re/Atum worship and the center of Egyptian solar theology. The great obelisks of Heliopolis (two of which are now the &#8220;Cleopatra's Needles&#8221; in London and New York) were sacred to the sun-god. The biblical connection: Joseph's father-in-law Potiphera was a priest at On (Gen 41:45), and Moses likely had some exposure to its religious tradition. Bubastis (<em>Pi-beseth</em>, Egyptian <em>Per-Bastet</em>) was the center of Bastet worship — the cat/lion-headed goddess — and served as a capital during the 22nd-23rd Dynasties. Herodotus (2.59-60) describes its famous annual festival with great crowds traveling by ship on the Nile canals.</p>",
    "18": "<p>Tahpanhes (Hebrew <em>Tachpanes</em>, Greek <em>Daphnai</em>, modern Tell Defenneh) was a Delta fortress city near the northeastern border where the Egyptian army maintained a garrison. After Jerusalem's fall (586 BCE), Johanan son of Kareah led Judean refugees to Tahpanhes against Jeremiah's counsel (Jer 43:1-7), and Jeremiah himself ended his ministry there. The clay bricks he buried at Tahpanhes (Jer 43:9-10) were the sign of Nebuchadnezzar's throne being set there. Archaeological excavations at Tell Defenneh revealed a large brick platform and Egyptian garrison fortress, confirming the biblical description. The &#8220;breaking of Egypt's yokes&#8221; (<em>shavar matotvot Mitzrayim</em>) = the end of Egyptian imperial power over subject nations.</p>",
    "19": "<p>&#8220;Thus I will execute judgments in Egypt, and they will know that I am the LORD&#8221; — the closing knowledge formula seals the city-catalog oracle. The executed judgments are not arbitrary violence but legal sentences: YHWH is the divine judge executing covenant-curses against a nation that violated the created moral order (claiming divine status, making the Nile its own, functioning as a broken staff to dependent peoples). The plural &#8220;judgments&#8221; (<em>shfatim</em>) echoes the Exodus vocabulary — in Exod 7:4 YHWH brings &#8220;great acts of judgment&#8221; against Egypt through the plagues; here the same word describes the Babylonian conquest as a second round of divine judgment on Egypt.</p>",
    "20": "<p>The date — &#8220;eleventh year, first month, seventh day&#8221; = April 29, 587 BCE — is one of only three oracles dated to the active siege period (alongside 24:1 and 29:1). The siege of Jerusalem is ongoing; the context is Hophra's recent failed relief attempt. This oracle provides the theological explanation for the failed intervention: YHWH has broken Pharaoh's arm and will not heal it. The date in the first month (spring) suggests proximity to the Passover — YHWH's original act of judgment against Egypt — making the broken-arm oracle a commentary on the theological continuity: what YHWH did to Egypt at the Exodus, he is doing again.</p>",
    "21": "<p>&#8220;I have broken the arm of Pharaoh king of Egypt, and it has not been bound up to heal it&#8221; — the &#8220;arm&#8221; (<em>zeroa</em>) is the standard symbol of military power in the OT (YHWH's &#8220;mighty arm&#8221; in the Exodus; the warrior's bared arm in Isa 52:10; Ezek 4:7). Pharaoh Hophra (Greek <em>Apries</em>, reigned 589-570 BCE) had marched his army toward Jerusalem (Jer 37:5-11) — the Babylonians temporarily lifted the siege, Judean defenders relaxed, and then Hophra withdrew without engaging, the Babylonians returned, and Jerusalem's fate was sealed. &#8220;Not bound up to heal it&#8221; — YHWH refuses to allow Egypt's military recovery; the arm broken by Hophra's failure will remain broken. The healing-of-wounds imagery echoes Hosea 5:13 (Israel seeking healing from Assyria and finding none) and Jer 30:12-13 (YHWH refusing to bind up Israel's wounds in judgment).</p>",
    "22": "<p>&#8220;I will break his arms, both the strong one and the already broken one&#8221; — the &#8220;strong arm&#8221; is the remaining military capacity after Hophra's failed expedition; the &#8220;already broken arm&#8221; is the withdrawal from Jerusalem. YHWH will complete the disable: Egypt's future military campaigns will also fail. The historical correspondence: Hophra was eventually overthrown by his own general Ahmose II (Amasis, ca. 570 BCE) after a military disaster in Libya — the final confirmation that Egypt's arms were broken. &#8220;I will make the sword fall from his hand&#8221; — the dramatic image of a warrior's sword dropping from a broken arm; Egypt will not be able to wield it.</p>",
    "23": "<p>&#8220;I will scatter the Egyptians among the nations&#8221; — the scattering of Egypt among the nations (v. 23) and the strengthening of Babylon's arms (v. 24) are parallel and opposite actions: YHWH weakens the one and strengthens the other. The scattering of a defeated people across the known world was standard Babylonian administrative policy — attested in the deportations of Israelites, Judeans, Phoenicians, and eventually Egyptians. Ezekiel's exilic community would have recognized this vocabulary immediately as the experience they were living.</p>",
    "24": "<p>&#8220;I will strengthen the arms of the king of Babylon and put my sword in his hand; but I will break Pharaoh's arms&#8221; — the spatial opposition (Babylon's arms strengthened; Pharaoh's broken) makes the transfer of divine mandate explicit. The sword that falls from Pharaoh's broken arm (v. 22) is placed in Nebuchadnezzar's hand (v. 24). This is the theological heart of chs. 29-32: the transfer of world-historical primacy from Egypt to Babylon is YHWH's sovereign act, not merely the outcome of military superiority. &#8220;He will groan before him with the groaning of a mortally wounded man&#8221; (<em>venehom lefanaiv nehamat chalal</em>) — the death-moan of a war-casualty is the metaphor for Egypt's defeat-cry before Nebuchadnezzar.</p>",
    "25": "<p>The knowledge formula appears again (&#8220;they will know that I am the LORD&#8221;) but with additional specification: &#8220;when I put my sword in the hand of the king of Babylon and he extends it over the land of Egypt.&#8221; The knowing that YHWH is LORD comes through Nebuchadnezzar's sword. This is consistent with Ezekiel's consistent use of Babylonian military victory as YHWH's self-revelation instrument — even the instruments of judgment serve the divine purpose of making YHWH known. The nations, including Egypt, will come to know YHWH not through blessing and prosperity but through the experience of his sovereignty in judgment.</p>",
    "26": "<p>The oracle concludes with the scattering-and-knowing formula one final time: &#8220;I will scatter the Egyptians among the nations and disperse them through the lands; and they will know that I am the LORD.&#8221; The pairing of scattering with knowing has a paradoxical quality: Egypt scattered among the nations will know YHWH — but only in the context of displacement and defeat. The Egyptian diaspora created by Nebuchadnezzar's campaigns and the later Persian conquest would have brought Egyptians into contact with Israelite and Jewish communities who could explain the theological meaning of these events. Knowledge of YHWH comes through suffering, not through success — a consistent theme in Ezekiel's foreign-nation oracles.</p>"
  },
  "31": {
    "1": "<p>The date — &#8220;eleventh year, first day of the third month&#8221; = June 21, 587 BCE — places this oracle approximately two months after 30:20 and still during the siege. By this date, Hophra's relief attempt has already failed, and Jerusalem's fall is perhaps two months away (Jerusalem fell in the fourth month of the eleventh year, 2 Kings 25:2-3). The cedar allegory addresses Pharaoh but uses Assyria as the primary subject — a rhetorical device: &#8220;here is what happened to Assyria; now answer — who are you like?&#8221; The answer is: you are exactly like Assyria, and you will end exactly like Assyria. For Ezekiel's audience, Assyria's fall (612 BCE) was within living memory — the most dramatic imperial collapse in their lifetime before Babylon's rise.</p>",
    "2": "<p>&#8220;Whom are you like in your greatness?&#8221; (<em>el-mi dameita begadleykha</em>) — the comparison question introduces the allegory. By asking Pharaoh to identify his peer, YHWH is about to supply the answer: Assyria. The rhetorical question is a trap — Egypt's pride will identify its own counterpart, and the counterpart is now in ruins. The address to Pharaoh &#8220;and to his multitude&#8221; (<em>va-el hamono</em>) extends the comparison: not just the king but the entire Egyptian military and administrative apparatus are being addressed. The nation is the tree; the tree is the nation.</p>",
    "3": "<p>&#8220;Consider: Assyria was a cedar in Lebanon&#8221; — the cedar of Lebanon (<em>erez beLvanon</em>) was the premier royal symbol in ANE iconography. Lebanon's cedar forests were harvested for the most prestigious construction projects: Solomon's temple and palace (1 Kings 5:6-10), the Assyrian royal palaces at Nineveh and Khorsabad, the Babylonian temples. In Ugaritic mythology, the cedar forest on the divine mountain is the domain of the divine craftsman. The cedar's characteristics — great height, spreading branches, permanence, fragrance — made it the natural symbol for a great empire: rooted deeply, reaching high, providing shade for all. Assyria at its height (8th-7th centuries BCE) was exactly this: ruling from the Persian Gulf to Egypt, the largest empire the ancient world had yet seen.</p>",
    "4": "<p>&#8220;The waters made it great; the deep raised it up high&#8221; — the cosmic waters (<em>tehom</em>, the primordial deep) as the source of the tree's power. In Babylonian cosmology, rivers were the arteries of the deep; the great rivers of Mesopotamia (Tigris and Euphrates) flowed from the cosmic waters of the abyss to nourish the world. For Assyria this is geographic reality: the Tigris and Euphrates made Mesopotamia the most agriculturally productive region of the ancient Near East, providing the surplus that powered Assyrian imperial expansion. The &#8220;sending its streams to all the trees of the field&#8221; (<em>veyelaheykha tishaleach el-kol atzey hassadeh</em>) reflects the Mesopotamian irrigation system that spread water across the land.</p>",
    "5": "<p>&#8220;Therefore it grew taller than all the trees of the field&#8221; — Assyrian imperial power was the most extensive the ancient world had yet seen. Tiglath-Pileser III (745-727 BCE) reorganized Assyrian administration into a provincial system; Sargon II (722-705 BCE) conquered Samaria; Sennacherib (705-681 BCE) besieged Jerusalem and destroyed Babylon; Esarhaddon (681-669 BCE) conquered Egypt; Ashurbanipal (669-627 BCE) ruled from Egypt to Elam — the greatest territorial extent of any ancient empire to that point. The &#8220;abundant water&#8221; that produced the tree's superiority is the same theological point: Assyria's power came from YHWH's providential arrangement, not from Assyria's intrinsic greatness.</p>",
    "6": "<p>&#8220;All the birds of the sky nested in its boughs; under its branches all the beasts of the field gave birth; all great nations dwelt in its shade&#8221; — the cosmic tree that shelters all life is an ANE motif with deep roots. The sacred tree (<em>kiskanu</em> in Sumerian, or the &#8220;tree of life&#8221; imagery in Assyrian palace reliefs) symbolized divine order sustaining all living things. Ashurnasirpal II's palace at Nimrud featured elaborate tree-of-life reliefs with birds, animals, and worshippers — Ezekiel's audience in Babylon would have been surrounded by exactly this imagery. The critique is that Assyria claimed to be the cosmic-order tree but was in fact a natural tree that grew from created water, not from divine self-existence.</p>",
    "7": "<p>&#8220;Beautiful in his greatness, magnificent in the length of his branches, for his root drew from abundant waters&#8221; — the beauty of Assyrian imperial achievement is acknowledged: the palaces of Nineveh and Khorsabad were genuinely magnificent; the hanging gardens of Babylon (attributed to Nebuchadnezzar) impressed the ancient world. Ezekiel does not deny the beauty; he explains it — the root drew from the water YHWH provided, not from the tree's own power. The beauty belongs to the gift, not the recipient. This is the theological error of Assyrian (and Egyptian) pride: attributing to one's own glory what belongs to YHWH's provision.</p>",
    "8": "<p>&#8220;The cedars in the garden of God could not match him&#8221; — the &#8220;garden of God&#8221; (<em>gan el</em>) is the divine sanctuary-garden that appears also in Ezek 28:13 (Tyre's king in Eden). In Mesopotamian tradition, a divine garden-paradise existed at the source of the cosmic rivers; the Sumerian paradise (<em>Dilmun</em>) and the Akkadian garden of the gods are cognate traditions. The comparison to the garden of God's trees is extravagant: Assyria exceeded even the divine garden's finest specimens. This hyperbole makes the eventual downfall all the more dramatic — the greatest tree the world had ever seen, surpassing even the divine garden, was cut down. Nothing is too great for YHWH to fell.</p>",
    "9": "<p>&#8220;I made him beautiful with his many branches, so that all the trees of Eden in the garden of God envied him&#8221; — YHWH explicitly claims credit for Assyria's beauty: &#8220;I made him beautiful&#8221; (<em>asatihu yafeh</em>). The divine envy of the Eden trees is a striking mythological touch — even the heavenly garden's trees were envious of YHWH's masterwork. The theological point: Assyria's glory was entirely derived from YHWH's creative gift. The mistake of <em>hubris</em> is to receive divine gifts and attribute them to one's own nature or effort — the same mistake diagnosed in Tyre (28:2-5: &#8220;your heart has become proud and you have said I am a god&#8221;) and now in Assyria/Egypt.</p>",
    "10": "<p>&#8220;Because it grew tall and set its top among the clouds, and its heart was proud of its height&#8221; — the tall tree whose top reaches the clouds is the biblical image of imperial overreach. The Tower of Babel (Gen 11:4: &#8220;a tower with its top in the heavens&#8221;) uses the same vertical imagery for the pride that YHWH corrects. Nebuchadnezzar's dream of the great tree (Dan 4:10-12) is the same motif applied to Babylon. The &#8220;proud heart&#8221; (<em>gabhah levavo</em>) is the biblical diagnosis of hubris — pride of heart is the root sin that overreaches creaturely limits and claims divine standing (Prov 16:18; Isa 14:13-14).</p>",
    "11": "<p>&#8220;I gave him over to the hand of the mightiest of nations; he dealt with him accordingly&#8221; (<em>veetenou beyad el-atsim goyim oseh yaaseh lo</em>) — YHWH himself gives the proud tree to its destroyer. The &#8220;mightiest of nations&#8221; that destroyed Assyria is Babylon: the Medes and Babylonians together destroyed Nineveh in 612 BCE, and Babylonian forces ended the last Assyrian remnant at Carchemish in 605 BCE. The passive (&#8220;I gave him over&#8221;) is theological agency language — Babylon did the physical work, but YHWH executed the sentence. &#8220;I drove him out for his wickedness&#8221; (<em>berisha gerashtiv</em>) — the &#8220;drive out&#8221; verb is the same used for driving out the Canaanites from the land; Assyria is treated as the occupant of divinely owned cosmic territory, expelled for covenant-breach.</p>",
    "12": "<p>&#8220;Foreigners — the most ruthless of nations — cut him down and left him; his branches fell on the mountains and in all the valleys&#8221; — the &#8220;most ruthless of nations&#8221; is Ezekiel's standard Babylonian epithet. The falling branches across mountains and valleys vividly captures the territorial collapse of the Assyrian empire: its provincial territories (in Anatolia, Syria, the Levant, Egypt, and Mesopotamia) were rapidly redistributed after 612 BCE. The &#8220;peoples of the earth&#8221; who abandoned Assyria's shade refers to the subject nations that quickly realigned with Babylon after Assyria's fall — the political logic of the ancient Near East required allegiance to the dominant power, and Babylon replaced Assyria within a decade.</p>",
    "13": "<p>&#8220;On its fallen trunk all the birds of the sky will settle, and all the beasts of the field will gather on its boughs&#8221; — the reversal of vv. 5-6: where living animals nested in the living tree, now scavengers settle on the corpse-tree. The birds and beasts that were sheltered by the great empire now feed on its remains. The imagery is of battlefield carrion-birds (Deut 28:26; Ezek 29:5; 32:4) — the fallen empire's remains become food for those it once sheltered. This reversal of patronage to predation is the economic reality of imperial collapse: subject peoples who depended on the empire become its looters after its fall.</p>",
    "14": "<p>&#8220;So that no tree beside the waters may exalt itself for its height&#8221; — the purpose clause reveals the reason for Assyria's fall: it is a lesson for all subsequent nations. No empire near the cosmic waters (no great nation with access to prosperity) should claim divine height based on its created resources. The phrase &#8220;given over to death, to the depths of the earth, among the children of men, with those who go down to the Pit&#8221; introduces the <em>Pit</em> (<em>bor</em>) / Sheol theme that dominates ch. 32 — the underworld as the common destiny of all great empires. &#8220;Children of men&#8221; (<em>beney adam</em>) — humanity in general, not specifically Israel; death is the universal equalizer across all national greatness.</p>",
    "15": "<p>&#8220;On the day he went down to Sheol I caused a mourning; I covered the deep over him&#8221; — YHWH mourns the fall of Assyria by covering the cosmic waters (tehom) — the same waters that fed Assyria's growth are now closed over it in a kind of cosmic funeral. This is one of the most theologically startling verses in Ezekiel: YHWH weeps over the empire he destroyed. The same divine pathos appears in Lam 3:33 (&#8220;he does not afflict from his heart or grieve the children of men&#8221;) and in Jesus weeping over Jerusalem (Luke 19:41) — divine judgment does not exclude divine grief over the judged. &#8220;Lebanon mourned for him, and all the trees of the field fainted on his account&#8221; — cosmic mourning: Lebanon's forests and the trees of the known world participated in the lament for fallen Assyria.</p>",
    "16": "<p>&#8220;I made the nations shake at the sound of his fall when I cast him down to Sheol with those who go down to the Pit&#8221; — the &#8220;shaking of nations&#8221; at Assyria's fall was a historical reality: Josiah's reforms (2 Kings 22-23) were possible precisely because Assyrian power was collapsing after Ashurbanipal's death (627 BCE); Egypt expanded northward; Babylon rose; Scythian raids destabilized the Levant. The collapse of Assyria sent shockwaves across the known world. &#8220;All the trees of Eden were comforted in the realm below&#8221; — the trees already in Sheol (previous empires) are &#8220;comforted&#8221; (<em>yenachamu</em>) by Assyria's arrival — the dark comfort of shared fate. This underworld-solidarity motif is developed more extensively in ch. 32.</p>",
    "17": "<p>&#8220;They too went down to Sheol with him — to those slain by the sword — even those who had been his arm and had dwelt under his shadow among the nations&#8221; — Assyria's vassal states and allied nations went to Sheol together with the empire. &#8220;His arm&#8221; (<em>zeroa</em>) = Assyria's military allies and instrument-nations; &#8220;dwelt under his shadow&#8221; = the client states that sheltered beneath Assyrian protection. The entire Assyrian political system — empire, vassals, tributaries, allies — descended together into the underworld. This is the historical picture of imperial collapse: the empire's destruction takes down the entire web of dependent relationships.</p>",
    "18": "<p>The application is made explicit: &#8220;To whom are you like in glory and greatness among the trees of Eden? You too will be brought down with the trees of Eden to the realm below.&#8221; The rhetorical question that opened the oracle (v. 2: &#8220;whom are you like?&#8221;) is now answered: you are like Assyria, and you will go to Sheol like Assyria. &#8220;You will lie among the uncircumcised with those slain by the sword&#8221; — the &#8220;uncircumcised&#8221; (<em>arlim</em>) category in Sheol is developed in ch. 32; here its first appearance prepares for the more elaborate Sheol gallery. &#8220;This is Pharaoh and all his multitude, declares the Lord GOD&#8221; — the closing identification formally applies the Assyria-allegory to Egypt, closing the interpretive frame.</p>"
  },
  "32": {
    "1": "<p>The date — &#8220;twelfth year, first day of the twelfth month&#8221; = March 3, 585 BCE — places this lament approximately 6-7 months after Jerusalem's fall (the city fell in the fourth/fifth month of the eleventh year). The news of Jerusalem's fall reached Ezekiel in the tenth month of the twelfth year (33:21 = January 585 BCE), but this oracle in the twelfth month comes 2-3 months after that devastating news. The dirge over Egypt is thus composed in the period immediately after Ezekiel learned definitively of Jerusalem's destruction — giving it a particular emotional weight. The prophet who mourned Jerusalem's fate is now pronouncing a formal lament over the empire that failed to save her.</p>",
    "2": "<p>The opening double image — &#8220;young lion among the nations&#8221; and &#8220;like a monster in the seas&#8221; (<em>vetannin bayamim</em>) — combines Egypt's two royal emblems. The lion was the universal ancient symbol of royal power and military strength: the Sphinx, the Egyptian royal title &#8220;strong bull,&#8221; and the lion-headed goddess Sekhmet were all royal symbols. The sea monster (<em>tannin</em>) returns from 29:3, where Pharaoh was the great sea creature lying in the Nile. &#8220;You burst forth in your rivers and troubled the waters with your feet and muddied their rivers&#8221; — the image of a powerful creature disturbing the waters is the opposite of Egypt's self-presentation: Egypt identified itself with the Nile's life-giving order, but YHWH sees only turbulence and muddying.</p>",
    "3": "<p>&#8220;I will throw my net over you with a host of many peoples, and they will haul you up in my net&#8221; — YHWH as divine fisherman with a net (&#8220;garnet&#8221; imagery) is distinct from the fish-hook of 29:4. The net captures larger prey and is operated by multiple people (&#8220;host of many peoples&#8221; = the coalition of nations Nebuchadnezzar commanded). The Babylonian army was multiethnic: it included Chaldean, Aramean, Median, and various Levantine contingents. In Egyptian royal iconography, the king hunted fish and fowl with nets in the marshes — YHWH reverses this: the royal fisherman becomes the fish caught in YHWH's net.</p>",
    "4": "<p>&#8220;I will throw you on dry land and hurl you into the open field&#8221; — removal from water to dry land reverses the sea-creature's natural habitat, replicating 29:5 (Pharaoh thrown into the wilderness). The bird- and beast-feeding imagery echoes the covenant-curse of Deut 28:26 and Jer 7:33. &#8220;Fill all the beasts of the earth with you&#8221; — the great sea creature that once consumed others becomes food for all. The ecological reversal (predator becomes prey) is the natural expression of divine poetic justice: Egypt, which fed on weaker nations, is itself consumed.</p>",
    "5": "<p>&#8220;I will lay your flesh on the mountains and fill the valleys with your remains&#8221; — the scale of the carnage suggests a total defeat: the mountains and valleys of Egypt covered with flesh. In ancient siege warfare, mass casualties were left unburied on the battlefield; the landscape of defeat was literally covered with the dead. The specific topographic mention (mountains and valleys) in a relatively flat country like Egypt suggests that the imagery is trans-local — the mountains are the mountains of neighboring lands where Egyptian armies fell, not just Egypt's own terrain.</p>",
    "6": "<p>&#8220;I will drench with your blood the land where you swim, even to the mountains; the ravines will be filled with you&#8221; — the blood-imagery continues the reversal: the Nile waters that &#8220;made Egypt great&#8221; (31:4) are now saturated with Pharaoh's blood. The Exodus connection is explicit: Exodus' first plague turned the Nile to blood (Exod 7:14-24). Here the blood of Egypt's judgment again flows through the Nile system — the second Egypt judgment mirrors the first. The theological pattern of Exodus-judgment repeated in Babylonian-conquest judgment is characteristic of prophetic typology.</p>",
    "7": "<p>&#8220;When I blot you out I will cover the heavens and darken their stars; I will cover the sun with a cloud and the moon will not give its light&#8221; — cosmic darkness is the most dramatic theophanic sign. The sun, moon, and stars were Egyptian deities: Re (the sun), Thoth (associated with the moon), and the stars as divine council members. YHWH darkening the Egyptian sky is a direct attack on Egyptian theology — the gods of Egypt are extinguished. The same darkness-judgment appeared as Egypt's ninth plague (Exod 10:21-23) and is applied eschatologically throughout the prophets (Isa 13:10 for Babylon; Joel 2:10, 3:15; Amos 8:9). The scale of cosmic darkness in response to Pharaoh's death expresses the world-historical significance of Egypt's fall.</p>",
    "8": "<p>&#8220;All the luminous lights of the sky I will darken over you&#8221; (<em>kol-meorey or bashamayim achshichem aleykha</em>) — the &#8220;luminous lights&#8221; include not only sun and moon but all the celestial bodies that regulated the Egyptian calendar, agricultural seasons, and religious festivals. Egyptian civilization was organized around precise solar observation (the solar calendar, the heliacal rising of Sirius heralding the Nile flood) — darkening these lights dismantles the Egyptian ordering of time and cosmos. &#8220;Bring darkness upon your land&#8221; — darkness in the land where light was most worshipped (the sun-cult of Re/Aten/Amun-Re) is the most targeted possible judgment.</p>",
    "9": "<p>&#8220;I will trouble the hearts of many peoples when I bring your ruin among the nations&#8221; — Egypt's fall was not a localized event; it reverberated through the international system. The &#8220;many peoples&#8221; whose hearts were troubled include Israel (who had relied on Egypt), the Cushites and Libyans (Egypt's southern and western neighbors), the remaining Phoenician city-states, and the smaller kingdoms of the Levant. &#8220;Countries you have not known&#8221; (<em>aratsot asher lo-yedatam</em>) — the news would travel to distant peoples who had never had direct contact with Egypt, carried by merchants, diplomats, and refugees.</p>",
    "10": "<p>&#8220;Their kings will shudder with horror when I brandish my sword before them; they will tremble continually, each man for his own life, on the day of your fall&#8221; — the neighboring kings' reaction to Egypt's fall is terror: if even Egypt falls, what are they? The phrase &#8220;brandish my sword before them&#8221; (<em>henif charbi al-pneyhem</em>) is YHWH as divine warrior displaying his weapon. In ANE royal iconography, the king brandishing weapons before enemies was the standard visual vocabulary of royal power; YHWH appropriates this imagery. The kings' trembling &#8220;each man for his own life&#8221; is the self-protective instinct of the vulnerable in the presence of overwhelming power.</p>",
    "11": "<p>&#8220;The sword of the king of Babylon will come against you&#8221; — after the extended metaphorical language of nets, fish, cosmic darkness, and sword-brandishing, the specific historical agent is named: Nebuchadnezzar. The transition from cosmic/metaphorical to specific/historical is characteristic of Ezekiel's prophetic technique: the cosmic frame interprets the historical event, and the historical event grounds the cosmic claim. Egypt's fall is simultaneously the fall of a chaos creature (vv. 2-10) and the conquest of a specific nation by a specific king in a specific historical period.</p>",
    "12": "<p>&#8220;By the swords of the mighty I will cause your multitude to fall — the most ruthless of nations, all of them; they will destroy the pride of Egypt, and all its multitude will be wiped out&#8221; — &#8220;the most ruthless of nations&#8221; (Babylon's epithet in Ezekiel) will &#8220;destroy the pride of Egypt&#8221; (<em>vishedu get Mitzrayim</em>). The &#8220;pride&#8221; (<em>gaon</em>) of Egypt was its claim to be the premier world power — the &#8220;pride of strength&#8221; promised to Israel in covenant blessing (Lev 26:19 — which became a curse when forfeited through disobedience) is here Egypt's national self-claim. The wiping out of Egypt's multitude mirrors the exile of Israel's multitude — same vocabulary, same theological structure.</p>",
    "13": "<p>&#8220;I will destroy all its livestock from beside the great waters&#8221; — Egyptian cattle were grazed on the Nile Delta's rich flood plains. The annual inundation deposited fertile silt that supported enormous herds; the destruction of livestock means the destruction of Egypt's agricultural economy. &#8220;No human foot will trouble them anymore, nor will the hooves of cattle disturb them&#8221; — the stillness of the desolated waters echoes v. 2 (Pharaoh muddied the rivers with his feet) — what Pharaoh did is undone; the waters are still but because there are no living beings to disturb them.</p>",
    "14": "<p>&#8220;Then I will let their waters settle and cause their rivers to flow like oil&#8221; (<em>az ashqia meymeyhem venahrotam kashemen olik</em>) — the tranquil flowing oil-rivers are the image of peaceful waters after judgment has cleared away the turbulence. In the ancient world, olive oil was the symbol of blessing, luxury, and peace. The Nile flowing like oil is Egypt at peace — but a peace of desolation, not prosperity. The rivers flow smoothly because nothing disturbs them; the land is empty. This is the dreadful peace of total defeat, contrasting with the muddied waters of Pharaoh's pride (v. 2).</p>",
    "15": "<p>&#8220;When I make the land of Egypt desolate and the land is stripped of everything it was filled with&#8221; — the stripping of the land (<em>veshomemotiy et-eretz Mitzrayim</em>) corresponds to the covenant-curse of Lev 26:32-35 applied to Israel (the land &#8220;stripped&#8221; and &#8220;desolate&#8221; while Israel is exiled). Egypt receives the same desolation-curse that YHWH applied to his own covenant people. &#8220;Then they shall know that I am the LORD&#8221; — the final knowledge formula in the oracle. Even the desolation of Egypt is a means of YHWH's self-revelation: the greatest empire of the ancient world laid waste demonstrates that YHWH alone is LORD.</p>",
    "16": "<p>&#8220;This is the lamentation they will sing over her; the daughters of the nations will sing this lamentation over Egypt and all its multitude&#8221; — the oracle formally identifies itself as a <em>qinah</em> (lament/dirge). &#8220;The daughters of the nations&#8221; (<em>benot hagoyim</em>) are the female mourners of neighboring nations who will sing Egypt's funeral song — the professional mourner tradition (&#8220;skilled women&#8221; of Jer 9:17; &#8220;daughters of music&#8221; in Qohelet 12:4) applied internationally. The nations mourn Egypt because Egypt's fall affects all of them — the loss of the great power leaves a void that all nations feel. Ezekiel's oracle itself is the <em>qinah</em> that the nations will sing.</p>",
    "17": "<p>The second date in ch. 32 — &#8220;twelfth year, fifteenth of the month&#8221; = March 17, 585 BCE — places the Sheol-descent oracle only two weeks after the first lamentation (v. 1, March 3). These two oracles together form the conclusion of the Egypt collection: first a lament (vv. 1-16), then a theological commentary on Egypt's place in the underworld gallery of fallen empires (vv. 17-32). The Sheol descent section is the final of the six Egypt oracles and brings the collection to a theological climax: Egypt joins Assyria, Elam, and the other great powers in the underworld community of the dishonored dead.</p>",
    "18": "<p>&#8220;Son of man, wail for the multitude of Egypt and bring them down — both Egypt and the daughters of the majestic nations — to the depths of the earth, with those who go down to the Pit&#8221; — Ezekiel is commanded to perform a prophetic wail that functions as an escort-to-Sheol. The &#8220;daughters of the majestic nations&#8221; (<em>banot hagoyim adirut</em>) are the subject nations and allies of Egypt who will accompany her into the underworld. In ANE tradition, a great king's death was accompanied by the deaths of servants, horses, and retinue — here the entire Egyptian imperial system descends together. The &#8220;Pit&#8221; (<em>bor</em>) is Sheol, the underworld — the place of the dead.</p>",
    "19": "<p>&#8220;Whom do you surpass in beauty? Go down and lie with the uncircumcised&#8221; — the rhetorical question challenges Egypt's self-image as the most beautiful and powerful of civilizations. Egyptian art and culture celebrated beauty (<em>neferet</em>, beautiful/good, is the root of &#8220;Nefertiti&#8221;) as a divine attribute; Egypt's temples, statues, and paintings are the most aesthetically sophisticated of the ancient world. &#8220;Go down and lie with the uncircumcised&#8221; — the command is the prophetic death-pronouncement; Sheol is the destination. &#8220;Uncircumcised&#8221; (<em>arlim</em>) in the context of Egypt is significant: Egypt practiced circumcision (attested in ancient Egyptian art and texts), so being associated with the uncircumcised is Egypt's ultimate ritual dishonor.</p>",
    "20": "<p>&#8220;They will fall among those slain by the sword; Egypt is delivered to the sword&#8221; — the passive &#8220;delivered&#8221; (<em>nitna lecherev</em>) places Egypt in the category of covenant-cursed nations: the same passive formula appears in Deut 1:27 (Israel feared YHWH had &#8220;delivered us into the hand of the Amorites&#8221;), Deut 20:13 (YHWH delivers cities into Israel's hand), and throughout Joshua for the nations given over to Israel. Now the formula is applied in reverse: YHWH delivers Egypt over to the sword. &#8220;Draw her down with all her multitude&#8221; (<em>mashkuha vekol-hamoneha</em>) — the prophetic command to drag Egypt into Sheol; Ezekiel's oracle is both the announcement and the execution of the sentence.</p>",
    "21": "<p>&#8220;The mightiest warriors will speak to him from the midst of Sheol&#8221; — in ANE underworld literature, the newly dead were greeted by the previously dead. The Babylonian Descent of Ishtar features the dead calling out to the goddess who has entered Sheol; the Akkadian Epic of Gilgamesh includes an underworld scene where Enkidu reports on the dead he encounters. Isaiah 14:9-10 has Sheol stirring to greet the fallen king of Babylon: &#8220;Even Sheol beneath is stirred up to meet you when you come ... all of them will respond and say to you: You too have become as weak as we!&#8221; Ezekiel's Sheol greeting follows the same literary convention.</p>",
    "22": "<p>Assyria in Sheol — &#8220;with all its company; their graves surround it — all of them slain, fallen by the sword.&#8221; Assyria fell with the destruction of Nineveh (612 BCE) by the combined Median and Babylonian forces. The Assyrian empire's fall was so sudden and complete that the subsequent generation found the ruins of Nineveh and could barely believe the mighty city had existed (Nahum and Zephaniah both record the astonishment at Nineveh's end). Assyria's &#8220;company&#8221; (<em>kehalo</em>) in Sheol — all the provincial armies, subject nations, and allied peoples who fell with it — is the ANE equivalent of a mass grave of empire.</p>",
    "23": "<p>&#8220;Its graves are in the depths of the Pit, its company gathered around its tomb — all slain, fallen by the sword, who had spread terror in the land of the living&#8221; — the phrase &#8220;spread terror in the land of the living&#8221; (<em>yitnu chittitam beeretz hahayyim</em>) is repeated eight times in vv. 23-32 as the refrain of the Sheol gallery. It is the common description of every fallen empire's earthly impact — what these nations shared in life was their capacity to terrorize. In Sheol this terror is gone: the same nations lie together as equals, powerless, sharing only the shame of violent death far from homeland.</p>",
    "24": "<p>Elam — &#8220;with all its multitude around its tomb — all slain, fallen by the sword, who went down uncircumcised to the depths of the earth.&#8221; Elam was the kingdom of SW Iran (modern Khuzestan) that maintained semi-independence against Assyrian and Babylonian pressure for centuries. Ashurbanipal conquered and devastated Elam ca. 645 BCE; Elam was subsequently absorbed into the Babylonian and then Persian empire. The uncircumcised designation for Elam is accurate: Elamite burial practices and iconography do not show evidence of circumcision. &#8220;Bear their shame with those who go down to the Pit&#8221; — the shame (<em>kalimmatam</em>) is the public dishonor of dying by the sword rather than by natural causes, without proper burial rites.</p>",
    "25": "<p>&#8220;They have made her a bed among the slain with all her multitude&#8221; — the &#8220;bed among the slain&#8221; (<em>mishkav betokh chalal</em>) is the underworld sleep of the battlefield dead. Elam's repetition (the name appears twice in this passage) may reflect the complexity of Elam's history — it was conquered and reconquered multiple times, unlike the more straightforwardly fallen Assyria. The theological function of the repetition is emphasis: even an ancient and resilient empire like Elam, which repeatedly rose from conquest, is finally and permanently in the company of the dishonored dead. Its resilience only made its final fall more instructive.</p>",
    "26": "<p>Meshech and Tubal — &#8220;with all their multitude; their graves surround them — all of them uncircumcised, slain by the sword, though they spread terror in the land of the living.&#8221; Meshech and Tubal are peoples from Anatolia: Meshech (<em>Musku</em> in Assyrian records) is associated with the Phrygians of central Turkey; Tubal (<em>Tabal</em>) with peoples of eastern Anatolia. They appear as slave and bronze traders in Ezek 27:13, suggesting commercial prominence. They also appear as Gog's associates in Ezek 38:2-3, giving them an eschatological dimension beyond their historical identity. By Ezekiel's time they had been subdued by Assyria and later Babylon, making their presence in the Sheol gallery historical rather than predictive.</p>",
    "27": "<p>&#8220;Do they not lie with the fallen warriors of old who went down to Sheol with their weapons of war, their swords placed under their heads and their shields covering their bones&#8221; — this verse introduces a distinction within Sheol between the honored dead (&#8220;fallen warriors of old&#8221; buried with weapons) and the dishonored dead (the nations listed). Warrior burial with weapons is attested archaeologically across the ancient world: Mycenaean shaft graves, Canaanite warrior burials, Assyrian royal tombs at Nimrud — elite soldiers were buried with their swords. The &#8220;warriors of old&#8221; (<em>giborey noflim me-olamim</em>) are the ancient heroic warriors of legend who died honorably in battle and were buried with military honors. Meshech and Tubal, by contrast, are &#8220;uncircumcised, slain by the sword&#8221; — same violent death but no ritual honor.</p>",
    "28": "<p>&#8220;You too will be shattered among the uncircumcised&#8221; — the direct address to Pharaoh resumes, applying the Sheol gallery to the current oracle's subject. After the catalogue of fallen nations, Egypt is told: you will join them. The verb &#8220;shattered&#8221; (<em>tishbar</em>) is the same used for breaking Pharaoh's arm (30:21-22) — the broken arm leads to the broken king in Sheol. Egypt will not receive the honor of the &#8220;warriors of old&#8221; but will lie in the shame category with all the uncircumcised nations listed above.</p>",
    "29": "<p>Edom — &#8220;its kings and all its princes — laid with those slain by the sword despite their might.&#8221; Edom was Israel's neighboring kingdom in the Negev/Transjordan region, descended from Esau. Edom's presence in the Sheol gallery is charged: Edom was condemned throughout the prophets for its assistance to Babylon during Jerusalem's fall (Ps 137:7; Obad 11-14; Jer 49:7-22; Ezek 25:12-14). &#8220;Despite their might&#8221; (<em>bgiburatam</em>) — Edom's fortress cities (Bozrah, Sela/Petra) were considered impregnable; Obadiah 3-4 addresses exactly this pride: &#8220;the pride of your heart has deceived you, you who live in the clefts of the rocks ... who say in your heart Who will bring me down?&#8221; YHWH brought Edom down along with all the others.</p>",
    "30": "<p>&#8220;All the princes of the north and all the Sidonians who have gone down with the slain — despite the terror they inspired, they are put to shame in their might&#8221; — the &#8220;princes of the north&#8221; (<em>nesiey tzafon</em>) are probably the Aramean and north Syrian rulers who had been Assyrian and Babylonian vassals. Sidon (the Phoenician city-state north of Tyre) fell to Babylon around 587-586 BCE, though the details are not fully documented. Sidon had been powerful enough to inspire terror — its navy and merchants dominated eastern Mediterranean trade. &#8220;Put to shame in their might&#8221; — the shame (<em>veyevoshu miguvratum</em>) echoes the Deuteronomic shame-formula (Deut 25:3); shame in Sheol is the permanent status of those who died without covenant honor.</p>",
    "31": "<p>&#8220;When Pharaoh sees them he will be comforted over all his multitude&#8221; — this is dark consolation: Pharaoh, arriving in Sheol to find Assyria, Elam, Edom, Meshech-Tubal, and Sidon already there, will be &#8220;comforted&#8221; (<em>venecham</em>) by the company. This is the bitter consolation that appears in Isa 14:9-11 for Babylon's king: &#8220;Sheol beneath is stirred up to meet you ... the worm is spread under you and worms cover you.&#8221; The &#8220;comfort&#8221; is real in a perverse sense: Pharaoh will not be alone in his shame, and will not be the worst or most disgraced of those in Sheol. Every great empire that preceded him arrived there first.</p>",
    "32": "<p>&#8220;For I spread his terror in the land of the living; yet Pharaoh and all his multitude will be laid among the uncircumcised with those slain by the sword, declares the Lord GOD&#8221; — the final verse completes the oracle with a theological summary statement. YHWH acknowledges that Egypt's terror in the land of the living was real — it was not imaginary or trivial. Egypt was genuinely powerful, genuinely terrifying to its neighbors. But the &#8220;yet&#8221; (<em>venitan</em>) is the theological pivot: earthly terror does not exempt from Sheol's equalizing judgment. The formula &#8220;laid among the uncircumcised with those slain by the sword&#8221; (<em>yutan betokh arlim et-challey cherev</em>) closes the oracle with the formula that has been the refrain of the entire Sheol gallery — Egypt joins the community of shame alongside every empire that claimed divine permanence and found only the Pit.</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'ezekiel')
    merge_comm(existing, EZEKIEL_CONTEXT)
    save_comm('mkt-context', 'ezekiel', existing)
    for ch in ['29', '30', '31', '32']:
        vv = existing.get(ch, {})
        print(f'  ch{ch}: {len(vv)} verse(s) with context commentary')

if __name__ == '__main__':
    main()
